// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below

//KT REQUEST FEATURE

var allow = false;

//New Request or Request Completed
if (current.parent == "" || current.u_status == "Completed")  allow = false;

//Existing Request
if (current.parent != "" && current.u_status == "In progress" ) {

	if (current.u_request_type == "Reassignment") {
		allow = new uiConditionCheck().RespondReassignment(current);
	}

	if (current.u_request_type == "Extension") {
		allow = new uiConditionCheck().RespondExtension(current);
	}

	if (current.u_request_type == "Clarification") {
		allow = new uiConditionCheck().RespondClarification(current);
	}

}


answer = allow;
